from dataclasses import dataclass
from typing import List, Dict

@dataclass
class FinOpsMetricSnapshot:
    """Daily snapshot of key FinOps metrics for dashboard ingestion."""
    date: str              # ISO date
    team_id: str
    spend_usd: float       # spend on this date
    conversation_count: int
    active_users: int
    cache_hit_rate: float  # 0.0–1.0

    @property
    def cost_per_conversation(self) -> float:
        return self.spend_usd / max(self.conversation_count, 1)

    @property
    def cost_per_active_user(self) -> float:
        return self.spend_usd / max(self.active_users, 1)

def aggregate_monthly(
    daily_snapshots: List[FinOpsMetricSnapshot],
    team_id: str,
    period: str,     # "2026-07"
) -> Dict[str, float]:
    team_days = [s for s in daily_snapshots
                 if s.team_id == team_id and s.date.startswith(period)]
    if not team_days:
        return {}
    total_spend = sum(s.spend_usd for s in team_days)
    total_convs = sum(s.conversation_count for s in team_days)
    total_users = sum(s.active_users for s in team_days)   # unique users would require dedup
    avg_cache = sum(s.cache_hit_rate for s in team_days) / len(team_days)
    return {
        "period": period,
        "team_id": team_id,
        "total_spend_usd": round(total_spend, 2),
        "cost_per_conversation": round(total_spend / max(total_convs, 1), 6),
        "avg_cache_hit_rate": round(avg_cache, 3),
    }

from dataclasses import dataclass
from typing import Optional, Callable
import statistics

@dataclass
class UnitMetricAlert:
    metric_name: str
    team_id: str
    current_value: float
    baseline_value: float     # trailing 3-month average
    threshold_pct: float      # alert if deviation > this %

    @property
    def deviation_pct(self) -> float:
        if self.baseline_value == 0:
            return 0.0
        return (self.current_value - self.baseline_value) / self.baseline_value * 100

    @property
    def should_alert(self) -> bool:
        return abs(self.deviation_pct) > self.threshold_pct

    def alert_message(self) -> Optional[str]:
        if not self.should_alert:
            return None
        direction = "increased" if self.deviation_pct > 0 else "decreased"
        return (
            f"ALERT: {self.metric_name} for {self.team_id} has {direction} "
            f"{abs(self.deviation_pct):.1f}% vs. baseline "
            f"(current: {self.current_value:.4f}, baseline: {self.baseline_value:.4f})"
        )

# Example
alert = UnitMetricAlert(
    metric_name="cost_per_conversation_usd",
    team_id="team-alpha",
    current_value=0.092,
    baseline_value=0.062,
    threshold_pct=20.0,
)
print(alert.alert_message())
# ALERT: cost_per_conversation_usd for team-alpha has increased 48.4% vs. baseline
